roadmaps.roadmap:
{
  "roadmap_title": "Dynamic Programming Mastery",
  "duration": "30 Days",
  "phases": [
    {
      "phase_title": "Phase 1: Fundamentals and Basics",
      "description": "Understand the basics of dynamic programming, memoization, and tabulation.",
      "core_topics": [
        "Introduction to Dynamic Programming",
        "Memoization vs Tabulation",
        "1D DP Basics: Fibonacci Series, Longest Common Subsequence"
      ]
    },
    {
      "phase_title": "Phase 2: 2D DP and Advanced Topics",
      "description": "Master 2D dynamic programming, and understand advanced topics like knapsack, matrix chain multiplication, and longest common subsequence.",
      "core_topics": [
        "2D DP Basics: Matrix Chain Multiplication",
        "Knapsack Problem: 0/1 Knapsack, Unbounded Knapsack",
        "Longest Common Subsequence: 1D, 2D, and Optimized Solutions"
      ]
    },
    {
      "phase_title": "Phase 3: Practice and Real-World Applications",
      "description": "Apply dynamic programming to solve real-world problems, and practice solving problems on platforms like LeetCode, HackerRank.",
      "core_topics": [
        "Dynamic Programming in Real-World Applications",
        "Practice Problems: LeetCode, HackerRank, and others",
        "Common Mistakes and Best Practices"
      ]
    }
  ]
}
